import React from 'react';
import styles from './Sidebar.module.css';

function Avatar({ name, size = 'md', online = false }) {
  const initials = name ? name[0].toUpperCase() : '?';
  return (
    <div className={`${styles.avatar} ${styles[size]} ${online ? styles.online : ''}`}>
      {initials}
    </div>
  );
}

export default function Sidebar({ user, onlineUsers, currentPeer, onSelectPeer, onLogout }) {
  return (
    <div className={styles.sidebar}>
      <div className={styles.header}>
        <div className={styles.brand}>
          <div className={styles.brandIcon}>💬</div>
          <span className={styles.brandName}>ChapApp</span>
        </div>
      </div>

      <div className={styles.sectionLabel}>Online Now</div>

      <div className={styles.list}>
        {onlineUsers.length === 0 ? (
          <div className={styles.empty}>No one else online yet…</div>
        ) : (
          onlineUsers.map(peer => {
  const isActive = currentPeer?.id === peer.id
  return (
    <button
      key={peer.id}
      className={`${styles.userItem} ${isActive ? styles.active : ''}`}
      onClick={() => onSelectPeer(peer)}  // peer already has { id, name }
    >
      <Avatar name={peer.name} size="sm" online />
      <div className={styles.userInfo}>
        <div className={styles.userName}>{peer.name}</div>
        <div className={styles.userSub}>Tap to chat</div>
      </div>
      <div className={styles.dot} />
    </button>
  )
})
        )}
      </div>

      <div className={styles.footer}>
        <Avatar name={user?.name || '?'} online />
        <div className={styles.userInfo}>
          <div className={styles.userName}>{user?.name}</div>
          <div className={styles.statusOnline}>● Online</div>
        </div>
        <button className={styles.logoutBtn} title="Sign out" onClick={onLogout}>⏻</button>
      </div>
    </div>
  );
}
